"use client";

import React, { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { motion, useTransform } from 'framer-motion';
import { ScrollProgressProps } from './types';
import { useScrollProgress } from './useScrollProgress';
import Tick from './Tick';
import { range } from './utils';

let audioCtx: AudioContext | null = null;
let lastPlayTime = 0;

function playClickSound(volume = 0.02) {
  if (typeof window === "undefined") return;
  const now = Date.now();
  if (now - lastPlayTime < 25) return; // Prevent overlapping on rapid scrolling
  lastPlayTime = now;

  try {
    const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
    if (!AudioContextClass) return;

    if (!audioCtx) {
      audioCtx = new AudioContextClass();
    }
    if (audioCtx.state === "suspended") {
      audioCtx.resume();
    }

    const osc = audioCtx.createOscillator();
    const gain = audioCtx.createGain();

    osc.type = "sine";
    osc.frequency.setValueAtTime(2200, audioCtx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(140, audioCtx.currentTime + 0.006);

    gain.gain.setValueAtTime(volume, audioCtx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.0001, audioCtx.currentTime + 0.006);

    osc.connect(gain);
    gain.connect(audioCtx.destination);

    osc.start();
    osc.stop(audioCtx.currentTime + 0.007);
  } catch (e) {}
}

export default function ScrollProgress({
  ticks = 42,
  color = "#a855f7",
  glow = true,
  height = 44,
  width = 320,
  variant = 'default',
}: ScrollProgressProps) {
  const [mounted, setMounted] = useState(false);
  const [isHovered, setIsHovered] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const { smoothProgress, scaleX: scaleY, glowIntensity } = useScrollProgress();

  const lastTickRef = useRef(-1);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    const unsubscribe = smoothProgress.on("change", (p) => {
      const currentTick = Math.round(p * (ticks - 1));
      if (currentTick !== lastTickRef.current) {
        lastTickRef.current = currentTick;
        playClickSound(0.015); // Satisfying mechanical tick sound
      }
    });
    return unsubscribe;
  }, [smoothProgress, ticks]);

  // Padding inside the vertical pill is py-5 (1.25rem / 20px) at top and bottom.
  // The first tick sits at 1.25rem and the last tick sits at 100% - 1.25rem.
  const indicatorTop = useTransform(smoothProgress, (p) => `calc(1.25rem + ${p} * (100% - 2.5rem))`);

  // Map glow intensity based on hover state combined with velocity:
  const overlayOpacity = useTransform(glowIntensity, (vIntensity) => {
    const baseGlow = isHovered ? 0.75 : 0.45;
    return Math.min(baseGlow + vIntensity, 0.95);
  });

  const overlayScale = useTransform(glowIntensity, (vIntensity) => {
    const baseScale = isHovered ? 1.25 : 1.0;
    return baseScale + vIntensity * 0.5;
  });

  const responsiveStyles = {
    maxHeight: `${width}px`,
  };

  // Drag interaction handler
  const handleDrag = (clientY: number) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const padding = 20; // 1.25rem top/bottom padding
    const usableHeight = rect.height - padding * 2;
    const relativeY = clientY - rect.top - padding;
    const progress = Math.max(0, Math.min(1, relativeY / usableHeight));

    const maxScroll = document.documentElement.scrollHeight - window.innerHeight;
    if (maxScroll > 0) {
      window.scrollTo(0, progress * maxScroll);
    }
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    e.preventDefault();
    setIsDragging(true);
    handleDrag(e.clientY);

    const handleMouseMove = (moveEvent: MouseEvent) => {
      handleDrag(moveEvent.clientY);
    };

    const handleMouseUp = () => {
      setIsDragging(false);
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };

    window.addEventListener('mousemove', handleMouseMove);
    window.addEventListener('mouseup', handleMouseUp);
  };

  if (!mounted) return null;

  return createPortal(
    <motion.div
      ref={containerRef}
      role="progressbar"
      aria-label="Page scroll progress"
      aria-valuemin={0}
      aria-valuemax={100}
      initial={{ opacity: 0, x: 20, scale: 0.95 }}
      animate={{ opacity: 1, x: 0, scale: 1 }}
      transition={{ duration: 0.6, type: "spring", stiffness: 100, damping: 15 }}
      whileHover={{ scale: 1.02 }}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onMouseDown={handleMouseDown}
      style={{
        ...responsiveStyles,
        width: `${height}px`, // Thickness (e.g. 44px)
        height: `${width}px`, // Length (e.g. 320px)
        position: 'fixed',
        right: '24px',
        top: '50%',
        y: '-50%',
        zIndex: 9999,
      }}
      className={`
        rounded-full backdrop-blur-md flex flex-col items-center py-5 relative overflow-hidden select-none cursor-pointer transition-colors duration-300
        ${variant === 'inverted'
          ? "bg-white/90 border border-black/10 shadow-[inset_1px_0_1px_rgba(255,255,255,0.8),0_10px_30px_rgba(0,0,0,0.12)]"
          : "bg-[#111111]/90 border border-white/10 shadow-[inset_1px_0_1px_rgba(255,255,255,0.05),0_10px_30px_rgba(0,0,0,0.5)]"
        }
        ${variant === 'inverted'
          ? (isHovered || isDragging ? "border-black/25" : "border-black/10")
          : (isHovered || isDragging ? "border-white/20" : "border-white/10")
        }
      `}
    >
      {/* Background Track Ticks Container (Vertical) */}
      <div className="flex flex-col justify-between items-center w-full h-full relative z-10">
        {range(ticks).map((i) => (
          <Tick
            key={i}
            index={i}
            totalTicks={ticks}
            smoothProgress={smoothProgress}
            variant={variant}
          />
        ))}
      </div>

      {/* Scroll Indicator (Vertical Placement) */}
      <motion.div
        style={{
          top: indicatorTop,
          y: '-50%',
          scaleY, // Vertical stretch on fast scroll
        }}
        className="absolute left-1/2 -translate-x-1/2 w-[16px] h-[4px] rounded-full z-20 pointer-events-none origin-center"
      >
        {/* Solid Purple Core Indicator */}
        <div 
          style={{ backgroundColor: color }}
          className="absolute inset-0 rounded-full animate-pulse-glow" 
        />

        {/* Ambient Neon Glow Overlay */}
        {glow && (
          <motion.div
            style={{
              backgroundColor: color,
              opacity: overlayOpacity,
              scale: overlayScale,
            }}
            className="absolute inset-0 rounded-full blur-[4px] -z-10"
          />
        )}
      </motion.div>
    </motion.div>,
    document.body
  );
}

"use client";

import { motion, useTransform, MotionValue } from 'framer-motion';

interface TickProps {
  index: number;
  totalTicks: number;
  smoothProgress: MotionValue<number>;
  variant?: 'default' | 'prominent' | 'inverted';
}

export default function Tick({ index, totalTicks, smoothProgress, variant = 'default' }: TickProps) {
  // Positional progress value for this tick (from 0 at first tick to 1 at last tick)
  const tickPos = totalTicks > 1 ? index / (totalTicks - 1) : 0;

  // Track absolute distance from this tick to current indicator progress
  const distance = useTransform(smoothProgress, (progress) => {
    return Math.abs(progress - tickPos);
  });

  const isProminentTick = variant === 'prominent' && index % 5 === 0;

  // Map ranges based on variant configuration
  let widthRange: number[];
  let opacityRange: number[];
  let bgRange: string[];

  if (variant === 'prominent') {
    if (isProminentTick) {
      // Prominent ticks are wider and very bright/visible, changing scale only slightly
      widthRange = [18, 16, 15];
      opacityRange = [0.95, 0.88, 0.8]; // Highly visible, light white
      bgRange = [
        'rgba(255, 255, 255, 0.95)',
        'rgba(255, 255, 255, 0.88)',
        'rgba(255, 255, 255, 0.8)'
      ];
    } else {
      // Regular ticks in prominent mode stay clearly visible, changing scale only slightly
      widthRange = [12, 11, 10];
      opacityRange = [0.65, 0.55, 0.45]; // Muted but very visible, no visibility animation fadeout
      bgRange = [
        'rgba(255, 255, 255, 0.65)',
        'rgba(255, 255, 255, 0.55)',
        'rgba(255, 255, 255, 0.45)'
      ];
    }
  } else {
    // Default or inverted mode ranges with standard dynamic breathing animations
    widthRange = [14, 12, 10];
    opacityRange = [0.85, 0.4, 0.12];
    bgRange = variant === 'inverted'
      ? [
          'rgba(0, 0, 0, 0.85)',
          'rgba(0, 0, 0, 0.35)',
          'rgba(0, 0, 0, 0.12)'
        ]
      : [
          'rgba(255, 255, 255, 0.85)',
          'rgba(255, 255, 255, 0.35)',
          'rgba(255, 255, 255, 0.12)'
        ];
  }

  const width = useTransform(distance, [0, 0.08, 0.18], widthRange);
  const opacity = useTransform(distance, [0, 0.08, 0.18], opacityRange);
  const background = useTransform(distance, [0, 0.08, 0.18], bgRange);

  return (
    <motion.div
      style={{
        width,
        opacity,
        background,
      }}
      className="h-[1.5px] rounded-full shrink-0 origin-center"
    />
  );
}

"use client";

import { useScroll, useSpring, useVelocity, useTransform } from 'framer-motion';

export function useScrollProgress() {
  const { scrollYProgress } = useScroll();

  // Custom buttery smooth spring behavior: stiffness: 120, damping: 25, mass: 0.6
  const smoothProgress = useSpring(scrollYProgress, {
    stiffness: 120,
    damping: 25,
    mass: 0.6,
  });

  // Calculate current scrolling velocity
  const scrollVelocity = useVelocity(smoothProgress);

  // Map velocity to horizontal stretch factor (scaleX)
  const scaleX = useTransform(scrollVelocity, (velocity) => {
    const absVelocity = Math.abs(velocity);
    // 1 is normal scale. Stretch increases with velocity, clamp max stretch to 2.5
    return 1 + Math.min(absVelocity * 12, 1.5);
  });

  // Map velocity to indicator glow intensity factor
  const glowIntensity = useTransform(scrollVelocity, (velocity) => {
    const absVelocity = Math.abs(velocity);
    return Math.min(absVelocity * 5, 0.9);
  });

  return {
    scrollYProgress,
    smoothProgress,
    scaleX,
    glowIntensity,
  };
}

export interface ScrollProgressProps {
  ticks?: number;
  color?: string;
  glow?: boolean;
  height?: number;
  width?: number;
  position?: 'top' | 'bottom';
  variant?: 'default' | 'prominent' | 'inverted';
}

/**
 * Generates an array of numbers from 0 to n-1.
 * Helper for generating ticks.
 */
export function range(n: number): number[] {
  return Array.from({ length: n }, (_, i) => i);
}

/**
 * Clamp a number between min and max bounds.
 */
export function clamp(value: number, min: number, max: number): number {
  return Math.max(min, Math.min(max, value));
}
